    after = [ "network-online.target" ];
    serviceConfig = {
      Type = "oneshot";
      RemainAfterExit = true;
      Restart = "on-failure";
      RestartSec = "5";
      StartLimitBurst = 10;
      StartLimitIntervalSec = 600;
